const OUTDIR="/tmp/claude-1000/-data-Brilliant-genomics-department/eb8d91f3-1707-45de-a10d-2de68fef6627/scratchpad/growthdb_work/lit/gemmine";
const BATCH=4;
const batches=[];for(let i=0;i<PAPERS.length;i+=BATCH)batches.push({idx:batches.length,paths:PAPERS.slice(i,i+BATCH)});
log(`GEM/MFA rate mine: ${PAPERS.length} papers in ${batches.length} batches of ${BATCH} (Opus)`);
const SUMMARY={type:'object',properties:{papers_processed:{type:'integer'},records_found:{type:'integer'},note:{type:'string'}},required:['papers_processed','records_found','note'],additionalProperties:false};
const BODY="You are a METABOLIC-FLUX DATA CURATOR mining genome-scale-metabolic-model and \u00b9\u00b3C-MFA papers for EXPERIMENTAL growth physiology used to build/validate models. Papers like these almost always report measured substrate uptake and product secretion rates (for model constraints/validation) or MFA-derived fluxes \u2014 FIND THEM. Be exhaustive; compute a derived rate ONLY from numbers explicitly in the paper and SHOW the arithmetic; never invent.\n\nRead each paper FULLY \u2014 Methods, Results, every table, model-validation sections, MFA sections, and in-text supplementary descriptions:\n${LIST}\n\nFor EACH distinct experimental growth condition of a prokaryote, produce ONE record. Prioritise conditions where MEASURED (not purely predicted) rates are reported. Capture:\n1. organism + strain.\n2. medium: name AND full composition (component + conc + unit) where stated; else composition:[], medium_composition_stated:false.\n3. conditions: culture_mode STRICTLY {batch, fed-batch, chemostat, turbidostat, retentostat, single-cell, co-culture} (+ culture_detail); oxygen STRICTLY {aerobic, anaerobic, microaerophilic, facultative} (+ aeration_detail); temperature_C; pH; dilution_rate_per_h.\n4. growth_rate_per_h (mu) + doubling_time_h \u2014 reported or CALCULATED (mu=ln2/td; mu=D at steady state; mu from OD slope). growth_method reported|calculated.\n5. uptake_rates: EVERY measured consumed substrate (carbon, O2, N, etc.) [{compound, rate, units (prefer mmol/gDW/h), method, is_experimental:true/false}]. Compute qS = mu/Yxs or delta-substrate/(biomass*time) when derivable. These experimental uptake rates are the priority.\n6. secretion_rates: EVERY measured excreted product (acetate, CO2, ethanol, formate, lactate, succinate, H2, etc.) [{compound, rate, units, method, is_experimental}].\n7. mfa_fluxes (if a \u00b9\u00b3C-MFA / flux-analysis paper): key net fluxes [{reaction_or_metabolite, flux, units, note}] \u2014 at least the exchange fluxes and central-carbon splits reported.\n8. yields {Yxs, product_yields}; source_snippet (verbatim <=300 chars); confidence; curation_notes (state every formula + the exact input numbers; note if a rate is cited FROM another paper and give that citation).\n\nOne paper often yields several records (strains \u00d7 conditions \u00d7 dilution rates). Emit each separately. If the paper reports NO experimental prokaryote rate, write {\"records\":[]}.\n\nCitation from article-meta; PMCID=file basename. Write JSON to this exact file (Write tool): ${OUTDIR}/batch_${IDX}.json\n{\"records\":[{\"pmcid\",\"paper_title\",\"first_author\",\"doi\",\"journal\",\"year\",\"organism\",\"strain\",\"medium_name\",\"medium_composition\":[{\"name\",\"amount\",\"unit\"}],\"medium_composition_stated\":true,\"culture_mode\",\"culture_detail\",\"oxygen\",\"aeration_detail\",\"temperature_C\",\"pH\",\"dilution_rate_per_h\",\"growth_rate_per_h\",\"doubling_time_h\",\"growth_method\",\"uptake_rates\":[{\"compound\",\"rate\",\"units\",\"method\",\"is_experimental\"}],\"secretion_rates\":[{\"compound\",\"rate\",\"units\",\"method\",\"is_experimental\"}],\"mfa_fluxes\":[{\"reaction_or_metabolite\",\"flux\",\"units\",\"note\"}],\"yields\":{},\"source_snippet\",\"confidence\",\"curation_notes\"}]}\n\nReturn: papers_processed, records_found, note.";
function prompt(b){return BODY.replace('${LIST}',b.paths.map(p=>'- '+p).join('\n')).replace('${OUTDIR}',OUTDIR).replace('${IDX}',String(b.idx));}
const results=await parallel(batches.map(b=>()=>agent(prompt(b),{label:`rates:${b.idx}`,phase:'Rates',model:'opus',effort:'high',schema:SUMMARY})));
const ok=results.filter(Boolean);const tr=ok.reduce((s,r)=>s+(r.records_found||0),0);const tp=ok.reduce((s,r)=>s+(r.papers_processed||0),0);
log(`GEM/MFA mine done: ${ok.length}/${batches.length} agents, ${tr} records from ${tp} papers`);
return {batches:batches.length,agents_ok:ok.length,papers_processed:tp,total_records:tr,outdir:OUTDIR};
